        ///<summary>
        ///Stake ALGO (≥ 1 ALGO) to open a USDC credit line.
        ///Preconditions:   - pay.receiver == application address   - pay.amount >= 1_000_000 (1 ALGO)   - stake_amount[sender] == 0 (not already registered)
        ///Mutates:   - stake_amount[sender] = pay.amount   - total_agents += 1
        ///</summary>
        /// <param name="pay"> </param>
